// Random ID Generators
// ─────────────────────────────────────────────────────────────────────────────

function generateRandomPNR() {
  let pnr = "8"; // first digit fixed

  for (let i = 0; i < 9; i++) {
    // digits from 1–9 only (no zero)
    pnr += Math.floor(Math.random() * 9) + 1;
  }

  return pnr;
}

function generateRandomTransactionID() {
  // Generate a 15-digit transaction ID
  return (100006000000000 + Math.floor(Math.random() * 1000000000)).toString();
}

